INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (1, 'Евреям 9:27', $body$И как человекам положено однажды умереть, а потом суд,$body$, 'verbatim', 1, NULL),
  (1, 'Иоанна 19:30', $body$Когда же Иисус вкусил уксуса, сказал: совершилось! И, преклонив главу, предал дух.$body$, 'verbatim', 2, NULL),
  (1, 'Луки 17:21', $body$и не скажут: вот, оно здесь, или: вот, там. Ибо вот, Царствие Божие внутрь вас есть.$body$, 'verbatim', 3, NULL),
  (1, 'Луки 16:19-31', $body$Некоторый человек был богат, одевался в порфиру и виссон и каждый день пиршествовал блистательно. Был также некоторый нищий, именем Лазарь, который лежал у ворот его в струпьях и желал напитаться крошками, падающими со стола богача, и псы, приходя, лизали струпья его. Умер нищий и отнесен был Ангелами на лоно Авраамово. Умер и богач, и похоронили его. И в аде, будучи в муках, он поднял глаза свои, увидел вдали Авраама и Лазаря на лоне его и, возопив, сказал: отче Аврааме! умилосердись надо мною и пошли Лазаря, чтобы омочил конец перста своего в воде и прохладил язык мой, ибо я мучаюсь в пламени сем. Но Авраам сказал: чадо! вспомни, что ты получил уже доброе твое в жизни твоей, а Лазарь — злое; ныне же он здесь утешается, а ты страдаешь; и сверх всего того между нами и вами утверждена великая пропасть, так что хотящие перейти отсюда к вам не могут, также и оттуда к нам не переходят. Тогда сказал он: так прошу тебя, отче, пошли его в дом отца моего, ибо у меня пять братьев; пусть он засвидетельствует им, чтобы и они не пришли в это место мучения. Авраам сказал ему: у них есть Моисей и пророки; пусть слушают их. Он же сказал: нет, отче Аврааме, но если кто из мертвых придет к ним, покаются. Тогда Авраам сказал ему: если Моисея и пророков не слушают, то если бы кто и из мертвых воскрес, не поверят.$body$, 'meaning', 4,
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (2, 'Иоанна 1:1', $body$В начале было Слово, и Слово было у Бога, и Слово было Бог.$body$, 'verbatim', 1, NULL),
  (2, 'Иоанна 6:63', $body$Дух животворит; плоть не пользует нимало. Слова, которые говорю Я вам, суть дух и жизнь.$body$, 'verbatim', 2, NULL),
  (2, 'Иоанна 4:24', $body$Бог есть дух, и поклоняющиеся Ему должны поклоняться в духе и истине.$body$, 'verbatim', 3, NULL),
  (2, 'Иоанна 1:14', $body$И Слово стало плотию, и обитало с нами, полное благодати и истины; и мы видели славу Его, славу, как Единородного от Отца.$body$, 'verbatim', 4, NULL),
  (2, 'Бытие 1:27', $body$И сотворил Бог человека по образу Своему, по образу Божию сотворил его; мужчину и женщину сотворил их.$body$, 'verbatim', 5, NULL),
  (2, 'Бытие 2:7', $body$И создал Господь Бог человека из праха земного, и вдунул в лице его дыхание жизни, и стал человек душею живою.$body$, 'verbatim', 6, NULL),
  (2, 'Бытие 1:28', $body$И благословил их Бог, и сказал им Бог: плодитесь и размножайтесь, и наполняйте землю, и обладайте ею, и владычествуйте над рыбами морскими [и над зверями,] и над птицами небесными, [и над всяким скотом, и над всею землею,] и над всяким животным, пресмыкающимся по земле.$body$, 'verbatim', 7, NULL),
  (2, 'Бытие 2:17', $body$а от дерева познания добра и зла не ешь от него, ибо в день, в который ты вкусишь от него, смертью умрешь.$body$, 'verbatim', 8, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (3, 'Бытие 3:1-6', $body$Змей был хитрее всех зверей полевых, которых создал Господь Бог. И сказал змей жене: подлинно ли сказал Бог: не ешьте ни от какого дерева в раю? И сказала жена змею: плоды с дерев мы можем есть, только плодов дерева, которое среди рая, сказал Бог, не ешьте их и не прикасайтесь к ним, чтобы вам не умереть. И сказал змей жене: нет, не умрете, но знает Бог, что в день, в который вы вкусите их, откроются глаза ваши, и вы будете, как боги, знающие добро и зло. И увидела жена, что дерево хорошо для пищи, и что оно приятно для глаз и вожделенно, потому что дает знание; и взяла плодов его и ела; и дала также мужу своему, и он ел.$body$, 'verbatim', 1, NULL),
  (3, 'Римлянам 3:23', $body$потому что все согрешили и лишены славы Божией$body$, 'verbatim', 2, NULL),
  (3, 'Иоанна 8:44', $body$Ваш отец диавол; и вы хотите исполнять похоти отца вашего. Он был человекоубийца от начала и не устоял в истине, ибо нет в нем истины. Когда говорит он ложь, говорит свое, ибо он лжец и отец лжи.$body$, 'verbatim', 3, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (4, 'Деяния 13:14-45', $body$Они же, проходя от Пергии, прибыли в Антиохию Писидийскую и, войдя в синагогу в день субботний, сели. После чтения закона и пророков, начальники синагоги послали сказать им: мужи братия! если у вас есть слово наставления к народу, говорите. Павел, встав и дав знак рукою, сказал: мужи Израильтяне и боящиеся Бога! послушайте. Бог народа сего избрал отцов наших и возвысил сей народ во время пребывания в земле Египетской, и мышцею вознесенною вывел их из нее, и около сорока лет времени питал их в пустыне. И, истребив семь народов в земле Ханаанской, разделил им в наследие землю их. И после сего, около четырехсот пятидесяти лет, давал им судей до пророка Самуила. Потом просили они царя, и Бог дал им Саула, сына Кисова, мужа из колена Вениаминова. Так прошло лет сорок. Отринув его, поставил им царем Давида, о котором и сказал, свидетельствуя: нашел Я мужа по сердцу Моему, Давида, сына Иессеева, который исполнит все хотения Мои. Из его-то потомства Бог по обетованию воздвиг Израилю Спасителя Иисуса. Перед самым явлением Его Иоанн проповедывал крещение покаяния всему народу Израильскому. При окончании же поприща своего, Иоанн говорил: за кого почитаете вы меня? я не тот; но вот, идет за мною, у Которого я недостоин развязать обувь на ногах. Мужи братия, дети рода Авраамова, и боящиеся Бога между вами! вам послано слово спасения сего. Ибо жители Иерусалима и начальники их, не узнав Его и осудив, исполнили слова пророческие, читаемые каждую субботу, и, не найдя в Нем никакой вины, достойной смерти, просили Пилата убить Его. Когда же исполнили всё написанное о Нем, то, сняв с древа, положили Его во гроб. Но Бог воскресил Его из мертвых. Он в продолжение многих дней являлся тем, которые вышли с Ним из Галилеи в Иерусалим и которые ныне суть свидетели Его перед народом. И мы благовествуем вам, что обетование, данное отцам, Бог исполнил нам, детям их, воскресив Иисуса, как и во втором псалме написано: Ты Сын Мой: Я ныне родил Тебя. А что воскресил Его из мертвых, так что Он уже не обратится в тление, о сем сказал так: Я дам вам милости, обещанные Давиду, верно. Посему и в другом месте говорит: не дашь Святому Твоему увидеть тление. Давид, в свое время послужив изволению Божию, почил и приложился к отцам своим, и увидел тление; а Тот, Которого Бог воскресил, не увидел тления. Итак, да будет известно вам, мужи братия, что ради Него возвещается вам прощение грехов; и во всем, в чем вы не могли оправдаться законом Моисеевым, оправдывается Им всякий верующий. Берегитесь же, чтобы не пришло на вас сказанное у пророков: смотрите, презрители, подивитесь и исчезните; ибо Я делаю дело во дни ваши, дело, которому не поверили бы вы, если бы кто рассказывал вам. При выходе их из Иудейской синагоги язычники просили их говорить о том же в следующую субботу. Когда же собрание было распущено, то многие Иудеи и чтители Бога, обращенные из язычников, последовали за Павлом и Варнавою, которые, беседуя с ними, убеждали их пребывать в благодати Божией. В следующую субботу почти весь город собрался слушать слово Божие. Но Иудеи, увидев народ, исполнились зависти и, противореча и злословя, сопротивлялись тому, что говорил Павел.$body$, 'meaning', 1,
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (5, 'Иоанна 8:44', $body$Ваш отец диавол; и вы хотите исполнять похоти отца вашего. Он был человекоубийца от начала и не устоял в истине, ибо нет в нем истины. Когда говорит он ложь, говорит свое, ибо он лжец и отец лжи.$body$, 'verbatim', 1, NULL),
  (5, 'Ефесянам 2:1', $body$И вас, мертвых по преступлениям и грехам вашим,$body$, 'verbatim', 2, NULL),
  (5, 'Ефесянам 2:2', $body$в которых вы некогда жили, по обычаю мира сего, по воле князя, господствующего в воздухе, духа, действующего ныне в сынах противления,$body$, 'verbatim', 3, NULL),
  (5, 'Матфея 11:28', $body$Придите ко Мне все труждающиеся и обремененные, и Я успокою вас;$body$, 'verbatim', 4, NULL),
  (5, 'Деяния 8:4-8', $body$Между тем рассеявшиеся ходили и благовествовали слово. Так Филипп пришел в город Самарийский и проповедывал им Христа. Народ единодушно внимал тому, что говорил Филипп, слыша и видя, какие он творил чудеса. Ибо нечистые духи из многих, одержимых ими, выходили с великим воплем, а многие расслабленные и хромые исцелялись. И была радость великая в том городе.$body$, 'verbatim', 5, NULL),
  (5, 'Евреям 9:27', $body$И как человекам положено однажды умереть, а потом суд,$body$, 'verbatim', 6, NULL),
  (5, 'Исход 20:4-5', $body$Не делай себе кумира и никакого изображения того, что на небе вверху, и что на земле внизу, и что в воде ниже земли; не поклоняйся им и не служи им, ибо Я Господь, Бог твой, Бог ревнитель, наказывающий детей за вину отцов до третьего и четвертого рода, ненавидящих Меня,$body$, 'verbatim', 7, NULL),
  (5, 'Луки 16:19-31', $body$Некоторый человек был богат, одевался в порфиру и виссон и каждый день пиршествовал блистательно. Был также некоторый нищий, именем Лазарь, который лежал у ворот его в струпьях и желал напитаться крошками, падающими со стола богача, и псы, приходя, лизали струпья его. Умер нищий и отнесен был Ангелами на лоно Авраамово. Умер и богач, и похоронили его. И в аде, будучи в муках, он поднял глаза свои, увидел вдали Авраама и Лазаря на лоне его и, возопив, сказал: отче Аврааме! умилосердись надо мною и пошли Лазаря, чтобы омочил конец перста своего в воде и прохладил язык мой, ибо я мучаюсь в пламени сем. Но Авраам сказал: чадо! вспомни, что ты получил уже доброе твое в жизни твоей, а Лазарь — злое; ныне же он здесь утешается, а ты страдаешь; и сверх всего того между нами и вами утверждена великая пропасть, так что хотящие перейти отсюда к вам не могут, также и оттуда к нам не переходят. Тогда сказал он: так прошу тебя, отче, пошли его в дом отца моего, ибо у меня пять братьев; пусть он засвидетельствует им, чтобы и они не пришли в это место мучения. Авраам сказал ему: у них есть Моисей и пророки; пусть слушают их. Он же сказал: нет, отче Аврааме, но если кто из мертвых придет к ним, покаются. Тогда Авраам сказал ему: если Моисея и пророков не слушают, то если бы кто и из мертвых воскрес, не поверят.$body$, 'meaning', 8,
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (6, 'Деяния 4:12', $body$ибо нет другого имени под небом, данного человекам, которым надлежало бы нам спастись.$body$, 'verbatim', 1, NULL),
  (6, 'Исаии 64:6', $body$Все мы сделались — как нечистый, и вся праведность наша — как запачканная одежда; и все мы поблекли, как лист, и беззакония наши, как ветер, уносят нас.$body$, 'verbatim', 2, NULL),
  (6, 'Колоссянам 2:8', $body$Смотрите, братия, чтобы кто не увлек вас философиею и пустым обольщением, по преданию человеческому, по стихиям мира, а не по Христу;$body$, 'verbatim', 3, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (7, 'Бытие 3:15', $body$и вражду положу между тобою и между женою, и между семенем твоим и между семенем ее; оно будет поражать тебя в голову, а ты будешь жалить его в пяту.$body$, 'verbatim', 1, NULL),
  (7, 'Исаии 7:14', $body$Итак Сам Господь даст вам знамение: се, Дева во чреве приимет и родит Сына, и нарекут имя Ему: Еммануил.$body$, 'verbatim', 2, NULL),
  (7, 'Матфея 1:21-23', $body$родит же Сына, и наречешь Ему имя Иисус, ибо Он спасет людей Своих от грехов их. А все сие произошло, да сбудется реченное Господом через пророка, который говорит: се, Дева во чреве приимет и родит Сына, и нарекут имя Ему Еммануил, что значит: с нами Бог.$body$, 'verbatim', 3, NULL),
  (7, 'Матфея 16:16', $body$Симон же Петр, отвечая, сказал: Ты — Христос, Сын Бога Живаго.$body$, 'verbatim', 4, NULL),
  (7, 'Иоанна 19:30', $body$Когда же Иисус вкусил уксуса, сказал: совершилось! И, преклонив главу, предал дух.$body$, 'verbatim', 5, NULL),
  (7, 'Иоанна 1:12', $body$А тем, которые приняли Его, верующим во имя Его, дал власть быть чадами Божиими,$body$, 'verbatim', 6, NULL),
  (7, 'Римлянам 10:9-10, 13', $body$Ибо если устами твоими будешь исповедывать Иисуса Господом и сердцем твоим веровать, что Бог воскресил Его из мертвых, то спасешься, потому что сердцем веруют к праведности, а устами исповедуют ко спасению. Ибо всякий, кто призовет имя Господне, спасется.$body$, 'verbatim', 7, NULL),
  (7, 'Откровение 3:20', $body$Се, стою у двери и стучу: если кто услышит голос Мой и отворит дверь, войду к нему, и буду вечерять с ним, и он со Мною.$body$, 'verbatim', 8, NULL),
  (7, 'Ефесянам 2:8-9', $body$Ибо благодатью вы спасены через веру, и сие не от вас, Божий дар: не от дел, чтобы никто не хвалился.$body$, 'verbatim', 9, NULL),
  (7, 'Иоанна 5:24', $body$Истинно, истинно говорю вам: слушающий слово Мое и верующий в Пославшего Меня имеет жизнь вечную, и на суд не приходит, но перешел от смерти в жизнь.$body$, 'verbatim', 10, NULL),
  (7, '1 Иоанна 5:13', $body$Сие написал я вам, верующим во имя Сына Божия, дабы вы знали, что вы, веруя в Сына Божия, имеете жизнь вечную.$body$, 'verbatim', 11, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (8, 'Иоанна 14:6', $body$Иисус сказал ему: Я есмь путь и истина и жизнь; никто не приходит к Отцу, как только через Меня.$body$, 'verbatim', 1, NULL),
  (8, 'Римлянам 8:2', $body$потому что закон духа жизни во Христе Иисусе освободил меня от закона греха и смерти.$body$, 'verbatim', 2, NULL),
  (8, '1 Иоанна 3:8', $body$Кто делает грех, тот от диавола, потому что сначала диавол согрешил. Для сего-то и явился Сын Божий, чтобы разрушить дела диавола.$body$, 'verbatim', 3, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, rubric)
VALUES
  (9, 'Иоанна 1:12', $body$А тем, которые приняли Его, верующим во имя Его, дал власть быть чадами Божиими,$body$, 'verbatim', 1, NULL),
  (9, '1 Коринфянам 3:16', $body$Разве не знаете, что вы храм Божий, и Дух Божий живет в вас?$body$, 'verbatim', 2, NULL),
  (9, 'Иоанна 14:13', $body$И если чего попросите у Отца во имя Мое, то сделаю, да прославится Отец в Сыне.$body$, 'verbatim', 3, NULL),
  (9, 'Луки 10:19', $body$се, даю вам власть наступать на змей и скорпионов и на всю силу вражью, и ничто не повредит вам;$body$, 'verbatim', 4, NULL),
  (9, 'Евреям 1:14', $body$Не все ли они суть служебные духи, посылаемые на служение для тех, которые имеют наследовать спасение?$body$, 'verbatim', 5, NULL),
  (9, 'Филиппийцам 3:20', $body$Наше же жительство — на небесах, откуда мы ожидаем и Спасителя, Господа нашего Иисуса Христа,$body$, 'verbatim', 6, NULL),
  (9, 'Матфея 28:18-20', $body$И приблизившись Иисус сказал им: дана Мне всякая власть на небе и на земле. Итак идите, научите все народы, крестя их во имя Отца и Сына и Святаго Духа, уча их соблюдать всё, что Я повелел вам; и се, Я с вами во все дни до скончания века. Аминь.$body$, 'verbatim', 7, NULL)
INSERT INTO block_locations_to_recite (block_id, reference, exact_text, check_mode, order_index, topic_label, rubric)
VALUES
  (10, '1 Иоанна 5:10-13', $body$Верующий в Сына Божия имеет свидетельство в себе самом; не верующий Богу представляет Его лживым, потому что не верует в свидетельство, которым Бог свидетельствовал о Сыне Своем. Свидетельство сие состоит в том, что Бог даровал нам жизнь вечную, и сия жизнь в Сыне Его. Имеющий Сына (Божия) имеет жизнь; не имеющий Сына Божия не имеет жизни. Сие написал я вам, верующим во имя Сына Божия, дабы вы знали, что вы, веруя в Сына Божия, имеете жизнь вечную.$body$, 'verbatim', 1, 'уверенность в спасении', NULL),
  (10, '1 Иоанна 1:9', $body$Если исповедуем грехи наши, то Он, будучи верен и праведен, простит нам грехи наши и очистит нас от всякой неправды.$body$, 'verbatim', 2, 'уверенность в прощении', NULL),
  (10, 'Иеремии 33:2-3', $body$так говорит Господь, Который сотворил [землю], Господь, Который устроил и утвердил ее, — Господь имя Ему: воззови ко Мне — и Я отвечу тебе, покажу тебе великое и недоступное, чего ты не знаешь.$body$, 'verbatim', 3, 'уверенность в молитве', NULL),
  (10, 'Притчи 3:5-6', $body$Надейся на Господа всем сердцем твоим, и не полагайся на разум твой. Во всех путях твоих познавай Его, и Он направит стези твои.$body$, 'verbatim', 4, 'уверенность в водительстве', NULL),
  (10, '1 Коринфянам 10:13', $body$Вас постигло искушение не иное, как человеческое; и верен Бог, Который не попустит вам быть искушаемыми сверх сил, но при искушении даст и облегчение, так чтобы вы могли перенести.$body$, 'verbatim', 5, 'уверенность в победе', NULL)
